+          message: `Relay could not open this project in ${editorLabel}. Make sure the \`${command}\` command is available on your PATH. ${
+            error.message
+          }`
+        });
+      });
+    });
+  } catch (error) {
+    const detail = error instanceof Error ? error.message : "Unknown launch error.";
+    return {
