 37	export const openProjectInEditor = async (
 38	  input: ProjectOpenInEditorInput,
 39	  spawnEditorProcess: SpawnEditorProcess
 40	): Promise<ProjectOpenInEditorResult> => {
 41	  const projectPath = typeof input.projectPath === "string" ? input.projectPath.trim() : "";
 42	  if (!projectPath) {
 43	    return { ok: false, message: "Relay could not open the project because the project path is empty." };
 44	  }
 45	  if (!isProjectEditorId(input.editorId)) {
 46	    return { ok: false, message: "Relay could not open the project because the selected editor is not supported." };
 47	  }
 48	
 49	  const command = projectEditorCommands[input.editorId];
 50	  const editorLabel = projectEditorLabels[input.editorId];
 51	
 52	  try {
 53	    const child = spawnEditorProcess(command, [projectPath]);
 54	    return await new Promise<ProjectOpenInEditorResult>((resolve) => {
 55	      let settled = false;
 56	      const settle = (result: ProjectOpenInEditorResult): void => {
 57	        if (settled) return;
 58	        settled = true;
 59	        resolve(result);
 60	      };
 61	
 62	      child.once("spawn", () => {
 63	        child.unref();
 64	        settle({ ok: true });
 65	      });
 66	      child.once("error", (error) => {
 67	        settle({
 68	          ok: false,
 69	          message: `Relay could not open this project in ${editorLabel}. Make sure the \`${command}\` command is available on your PATH. ${
 70	            error.message
 71	          }`
 72	        });
 73	      });
 74	    });
 75	  } catch (error) {
 76	    const detail = error instanceof Error ? error.message : "Unknown launch error.";
 77	    return {
 78	      ok: false,
 79	      message: `Relay could not open this project in ${editorLabel}. Make sure the \`${command}\` command is available on your PATH. ${detail}`
 80	    };
 81	  }
 82	};
