 6	const execFileAsync = promisify(execFile);
 7	
 8	export type CommandResult = {
 9	  readonly stdout: string;
10	  readonly stderr: string;
11	};
12	
13	export type CommandOptions = {
14	  readonly cwd?: string | undefined;
15	  readonly timeoutMs?: number | undefined;
16	  readonly maxBuffer?: number | undefined;
17	};
18	
19	export type CommandExecutorService = {
20	  readonly execFile: (command: string, args: readonly string[], options?: CommandOptions) => Effect.Effect<CommandResult, unknown>;
21	  readonly spawnDetached: (command: string, args: readonly string[]) => ChildProcess;
22	};
23	
24	export const CommandExecutor = Context.Service<CommandExecutorService>("relay/CommandExecutor");
25	
26	export const CommandExecutorLive = Layer.succeed(CommandExecutor)({
27	  execFile: (command, args, options = {}) =>
28	    Effect.tryPromise({
29	      try: () =>
30	        execFileAsync(command, [...args], {
31	          cwd: options.cwd,
32	          encoding: "utf8",
33	          maxBuffer: options.maxBuffer ?? 1024 * 1024,
34	          timeout: options.timeoutMs
35	        }).then((result) => ({
36	          stdout: result.stdout,
37	          stderr: result.stderr
38	        })),
39	      catch: (error) => error
40	    }),
41	  spawnDetached: (command, args) => spawn(command, [...args], { detached: true, stdio: "ignore" })
42	});
